BEGIN; CREATE TABLE IF NOT EXISTS public.profile_account_action_audit (id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY, profile_id uuid NOT NULL REFERENCES public.profiles(id), action text NOT NULL CHECK (action IN ('deactivated','restored')), reason text NOT NULL CHECK (char_length(btrim(reason)) BETWEEN 3 AND 500), acted_by uuid NOT NULL REFERENCES public.profiles(id), acted_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX IF NOT EXISTS idx_profile_account_action_audit_profile_time ON public.profile_account_action_audit(profile_id, acted_at DESC); ALTER TABLE public.profile_account_action_audit ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "profile_account_action_audit_select_admin" ON public.profile_account_action_audit; CREATE POLICY "profile_account_action_audit_select_admin" ON public.profile_account_action_audit FOR SELECT TO authenticated USING (public.is_admin()); REVOKE ALL ON TABLE public.profile_account_action_audit FROM PUBLIC, anon, authenticated; GRANT SELECT ON TABLE public.profile_account_action_audit TO authenticated; CREATE OR REPLACE FUNCTION public.profiles_guard_account_lifecycle_v1() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN IF OLD.deleted_at IS DISTINCT FROM NEW.deleted_at AND COALESCE(current_setting('app.profile_account_action_v1', true), '') <> 'on' THEN RAISE EXCEPTION 'Khong duoc doi trang thai ngung tai khoan truc tiep. Hay dung RPC quan tri tai khoan.' USING ERRCODE = '42501'; END IF; RETURN NEW; END; $$; DROP TRIGGER IF EXISTS trg_profiles_guard_account_lifecycle_v1 ON public.profiles; CREATE TRIGGER trg_profiles_guard_account_lifecycle_v1 BEFORE UPDATE OF deleted_at ON public.profiles FOR EACH ROW EXECUTE FUNCTION public.profiles_guard_account_lifecycle_v1(); CREATE OR REPLACE FUNCTION public.admin_deactivate_profiles_v1(p_profile_ids uuid[], p_reason text) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ DECLARE v_actor uuid := auth.uid(); v_ids uuid[]; v_reason text := btrim(COALESCE(p_reason, '')); v_count integer; v_now timestamptz := now(); BEGIN IF v_actor IS NULL OR NOT public.is_admin() THEN RAISE EXCEPTION 'Chi Admin dang hoat dong moi duoc ngung tai khoan.' USING ERRCODE = '42501'; END IF; SELECT ARRAY(SELECT DISTINCT u.profile_id FROM unnest(COALESCE(p_profile_ids, ARRAY[]::uuid[])) AS u(profile_id) WHERE u.profile_id IS NOT NULL ORDER BY u.profile_id) INTO v_ids; IF cardinality(v_ids) = 0 THEN RAISE EXCEPTION 'Chua chon tai khoan can ngung.'; END IF; IF cardinality(v_ids) > 100 THEN RAISE EXCEPTION 'Moi lan chi duoc ngung toi da 100 tai khoan.'; END IF; IF char_length(v_reason) < 3 OR char_length(v_reason) > 500 THEN RAISE EXCEPTION 'Ly do ngung tai khoan phai tu 3 den 500 ky tu.'; END IF; IF v_actor = ANY(v_ids) THEN RAISE EXCEPTION 'Khong the tu ngung tai khoan cua chinh minh.'; END IF; IF EXISTS (SELECT 1 FROM public.super_admins sa WHERE sa.user_id = ANY(v_ids)) THEN RAISE EXCEPTION 'Khong the ngung tai khoan Super Admin.'; END IF; PERFORM p.id FROM public.profiles p WHERE p.id = ANY(v_ids) ORDER BY p.id FOR UPDATE; SELECT count(*)::integer INTO v_count FROM public.profiles p WHERE p.id = ANY(v_ids); IF v_count <> cardinality(v_ids) THEN RAISE EXCEPTION 'Co tai khoan khong ton tai. Khong tai khoan nao bi thay doi.'; END IF; IF EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = ANY(v_ids) AND p.deleted_at IS NOT NULL) THEN RAISE EXCEPTION 'Co tai khoan da duoc ngung truoc do. Khong tai khoan nao bi thay doi.'; END IF; PERFORM set_config('app.profile_account_action_v1', 'on', true); UPDATE public.profiles SET deleted_at = v_now, is_active = false, is_approved = false WHERE id = ANY(v_ids); INSERT INTO public.profile_account_action_audit(profile_id, action, reason, acted_by, acted_at) SELECT u.profile_id, 'deactivated', v_reason, v_actor, v_now FROM unnest(v_ids) AS u(profile_id); RETURN v_count; END; $$; CREATE OR REPLACE FUNCTION public.admin_restore_profiles_v1(p_profile_ids uuid[], p_reason text) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ DECLARE v_actor uuid := auth.uid(); v_ids uuid[]; v_reason text := btrim(COALESCE(p_reason, '')); v_count integer; v_now timestamptz := now(); BEGIN IF v_actor IS NULL OR NOT public.is_admin() THEN RAISE EXCEPTION 'Chi Admin dang hoat dong moi duoc khoi phuc tai khoan.' USING ERRCODE = '42501'; END IF; SELECT ARRAY(SELECT DISTINCT u.profile_id FROM unnest(COALESCE(p_profile_ids, ARRAY[]::uuid[])) AS u(profile_id) WHERE u.profile_id IS NOT NULL ORDER BY u.profile_id) INTO v_ids; IF cardinality(v_ids) = 0 THEN RAISE EXCEPTION 'Chua chon tai khoan can khoi phuc.'; END IF; IF cardinality(v_ids) > 100 THEN RAISE EXCEPTION 'Moi lan chi duoc khoi phuc toi da 100 tai khoan.'; END IF; IF char_length(v_reason) < 3 OR char_length(v_reason) > 500 THEN RAISE EXCEPTION 'Ly do khoi phuc phai tu 3 den 500 ky tu.'; END IF; PERFORM p.id FROM public.profiles p WHERE p.id = ANY(v_ids) ORDER BY p.id FOR UPDATE; SELECT count(*)::integer INTO v_count FROM public.profiles p WHERE p.id = ANY(v_ids); IF v_count <> cardinality(v_ids) THEN RAISE EXCEPTION 'Co tai khoan khong ton tai. Khong tai khoan nao bi thay doi.'; END IF; IF EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = ANY(v_ids) AND p.deleted_at IS NULL) THEN RAISE EXCEPTION 'Co tai khoan dang hoat dong, khong can khoi phuc. Khong tai khoan nao bi thay doi.'; END IF; PERFORM set_config('app.profile_account_action_v1', 'on', true); UPDATE public.profiles SET deleted_at = NULL, is_active = false, is_approved = false WHERE id = ANY(v_ids); INSERT INTO public.profile_account_action_audit(profile_id, action, reason, acted_by, acted_at) SELECT u.profile_id, 'restored', v_reason, v_actor, v_now FROM unnest(v_ids) AS u(profile_id); RETURN v_count; END; $$; CREATE OR REPLACE FUNCTION public.admin_list_deactivated_profiles_v1() RETURNS TABLE (id uuid, full_name text, role text, department text, is_active boolean, is_approved boolean, created_at timestamptz, deleted_at timestamptz, last_action_reason text, last_action_at timestamptz) LANGUAGE plpgsql SECURITY DEFINER STABLE SET search_path = public, pg_temp AS $$ BEGIN IF auth.uid() IS NULL OR NOT public.is_admin() THEN RAISE EXCEPTION 'Chi Admin dang hoat dong moi duoc xem tai khoan da ngung.' USING ERRCODE = '42501'; END IF; RETURN QUERY SELECT p.id, p.full_name, p.role::text, p.department::text, p.is_active, p.is_approved, p.created_at, p.deleted_at, a.reason, a.acted_at FROM public.profiles p LEFT JOIN LATERAL (SELECT x.reason, x.acted_at FROM public.profile_account_action_audit x WHERE x.profile_id = p.id ORDER BY x.acted_at DESC, x.id DESC LIMIT 1) a ON true WHERE p.deleted_at IS NOT NULL ORDER BY p.deleted_at DESC, p.created_at DESC; END; $$; REVOKE ALL ON FUNCTION public.admin_deactivate_profiles_v1(uuid[], text) FROM PUBLIC, anon, authenticated; REVOKE ALL ON FUNCTION public.admin_restore_profiles_v1(uuid[], text) FROM PUBLIC, anon, authenticated; REVOKE ALL ON FUNCTION public.admin_list_deactivated_profiles_v1() FROM PUBLIC, anon, authenticated; GRANT EXECUTE ON FUNCTION public.admin_deactivate_profiles_v1(uuid[], text) TO authenticated; GRANT EXECUTE ON FUNCTION public.admin_restore_profiles_v1(uuid[], text) TO authenticated; GRANT EXECUTE ON FUNCTION public.admin_list_deactivated_profiles_v1() TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
